  ('Quiz: CRM-mästaren', 'Quiz: The CRM master', 'Quiz: El maestro del CRM', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Fråga 1: "}, {"type": "text", "text": "När bör du skapa en lead i CRM:t?"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "A) Efter att affären är klar"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "B) Så fort du ser en möjlighet"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "C) Bara om kunden ber om det"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Rätt svar: "}, {"type": "text", "text": "B – Skapa leaden direkt – annars glöms möjligheten bort."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Fråga 2: "}, {"type": "text", "text": "Vad kännetecknar en lead som riskerar att dö?"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "A) Den har ett nästa steg"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "B) Den saknar nästa steg"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "C) Den har en bokad uppgift"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Rätt svar: "}, {"type": "text", "text": "B – En lead utan nästa steg dör – boka alltid nästa steg."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Fråga 3: "}, {"type": "text", "text": "Vad är Sandbox-fliken till för?"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "A) Skarpa kunddata"}]}]}, 